using System;using FluentAssertions;using Xunit;using ATLAS.Kernel.Domain.Specifications;using System.Linq.Expressions;namespace ATLAS.Kernel.Tests.Domain.Specifications;public class SpecificationCompositionTests{    private class EvenSpec : Specification<int>    {        public override Expression<Func<int, bool>> ToExpression() => x => x % 2 == 0; }    private class Greater5Spec : Specification<int>    {        public override Expression<Func<int, bool>> ToExpression() => x => x > 5; }    [Fact]    public void And_Or_Not_Compose_Work()    {        var even = new EvenSpec();        var gt5 = new Greater5Spec();        Specification<int> and = even.And(gt5);        Specification<int> or = even.Or(gt5);        Specification<int> not = even.Not();        and.IsSatisfiedBy(8).Should().BeTrue();        and.IsSatisfiedBy(4).Should().BeFalse();        or.IsSatisfiedBy(7).Should().BeTrue();        not.IsSatisfiedBy(3).Should().BeTrue();    }}